package com.restaurantcraft.block; import com.restaurantcraft.config.RestaurantCraftConfig; import net.minecraft.world.level.block.Block; import net.minecraft.world.level.block.state.BlockState; import net.minecraft.world.level.storage.loot.LootParams; import net.minecraft.world.item.ItemStack; import java.util.*; public class FoodDisplayBlock extends Block { public FoodDisplayBlock(Properties p){super(p);} public List<ItemStack> getDrops(BlockState s, LootParams.Builder b){ return RestaurantCraftConfig.allowFoodBlockDrop.get()?super.getDrops(s,b):List.of(); } }
